noncompliant:
// Noncompliant - switch without default clause
int foo = 42;
switch (foo)
{
    case 0:
        Console.WriteLine("foo = 0");
        break;
    case 42:
        Console.WriteLine("foo = 42");
        break;
    // No default clause - Noncompliant
}

compliant:
// Compliant - switch with default clause
int foo = 42;
switch (foo)
{
    case 0:
        Console.WriteLine("foo = 0");
        break;
    case 42:
        Console.WriteLine("foo = 42");
        break;
    default:
        Console.WriteLine("Unknown value");
        break;
}
